fastify.post(
  '/webhook',
  {
    config: { rawBody: true }, // enable raw body capture for this route
  },
  async (request, reply) => {
    const secret = process.env.PREMBLY_API_KEY;

    if (!secret) {
      request.log.error('PREMBLY_API_KEY environment variable is not set');
      return reply
        .status(500)
        .send({ error: 'Server misconfiguration: missing API key' });
    }

    const receivedSignature = request.headers['x-prembly-signature'];

    // Reject immediately when the header is absent
    if (!receivedSignature) {
      return reply.status(401).send({ error: 'Invalid signature' });
    }

    // Compute HMAC-SHA256 over the raw payload and Base64-encode it
    const hmac = crypto.createHmac('sha256', secret);
    hmac.update(request.rawBody); // request.rawBody is a Buffer
    const computedSignature = hmac.digest('base64');

    // Use a timing-safe comparison to prevent timing attacks
    const receivedBuf = Buffer.from(receivedSignature);
    const computedBuf = Buffer.from(computedSignature);

    const signaturesMatch =
      receivedBuf.length === computedBuf.length &&
      crypto.timingSafeEqual(receivedBuf, computedBuf);

    if (!signaturesMatch) {
      return reply.status(401).send({ error: 'Invalid signature' });
    }

    // Signature is valid — process the webhook payload
    request.log.info({ body: request.body }, 'Webhook received and verified');

    return reply.status(200).send({ status: 'received' });
  }
);

